import Animated, {useSharedValue, useAnimatedStyle, withTiming} from 'react-native-reanimated';
export function TopProgressBar({progress}: {progress: number}) { const w = useSharedValue(0); React.useEffect(() => { w.value = withTiming(progress, {duration: 300}); }, [progress]); const style = useAnimatedStyle(() => ({width: `${w.value * 100}%`})); return (<View style={s.track}><Animated.View style={[s.fill, style]}/></View>); }
