// FlipCard.tsx
import React from 'react';
import {StyleSheet, View, Pressable} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, useDerivedValue} from 'react-native-reanimated';
export function FlipCard({front, back}: {front: React.ReactNode; back: React.ReactNode}) { const r = useSharedValue(0); const flip = () => { r.value = withSpring(r.value === 0 ? 180 : 0, {damping: 18, stiffness: 200}); }; const frontStyle = useAnimatedStyle(() => ({transform: [{perspective: 800}, {rotateY: `${r.value}deg`}], opacity: r.value < 90 ? 1 : 0})); const backStyle = useAnimatedStyle(() => ({transform: [{perspective: 800}, {rotateY: `${r.value - 180}deg`}], opacity: r.value >= 90 ? 1 : 0})); return (<Pressable onPress={flip}><View><Animated.View style={[s.card, frontStyle]}>{front}</Animated.View><Animated.View style={[s.card, s.back, backStyle]}>{back}</Animated.View></View></Pressable>); }
const s = StyleSheet.create({card:{width:240, height:340, backgroundColor:'#1C1C1E', borderRadius:16, alignItems:'center', justifyContent:'center'}, back:{position:'absolute', top:0, left:0}});

